:root {
    --color-theme1: #017550;
    --color-theme2: #94A0D1;
    --color-theme3: #5D2E8F;
    --color-theme2-light: #B6DCAE;
    --color-theme3-light: #E6EDF4;
    --color-theme4-light: #f5fcff;
    --color-theme2-dark: #173f6c;
    --color-header: #017550;
    --color-footer:#017550;
    --font-family: "Lato", sans-serif;
}

[tabindex="-1"] {
  outline: 0;
}

body,
button,
input,
select,
textarea {
  font-size: 16px;
  line-height: 20px;
  -webkit-appearance: none;
  -moz-appearance: none;
  appearance: none;
  background: none;
  border: 0;
  border-radius: 0;
  /* color: #3f3f3f; */
  display: block;
 /*  font-family: sans-serif; */
   font-family: 'Lato', sans-serif;
  -moz-osx-font-smoothing: grayscale;
  -webkit-font-smoothing: antialiased;
  padding: 0;
}

html,
body {
  height: 100%;
  width: 100%;
  scrollbar-color: dark;
  scrollbar-width: thin;
}

a,
abbr {
  text-decoration: underline;
}

a {
  color: var(--color-theme1);
  font-weight: 900;
}
a:hover {
    color: var(--color-theme3);
   /* font-weight: 900; */
} 
body {
background-color: var(--color-theme4-light);
}

button {
  cursor: pointer;
}

em {
  font-style: italic;
}

/* hr {
  border: 0;
  margin: 0;
} */

hr {
    margin: 0;
    margin-top: 1rem !important;
    margin-bottom: 1rem !important;
    border-top: 1px solid var( --color-theme2) !important;
} 

main {
  display: block;
    border-left:1px solid #C9CFE8;
}

strong {
  font-weight: bold;
}

