.accordionheader .accordionheader-x-toggle {
    background-color: #fff;
    border-radius: 999999px;
    height: 24px;
   /* left: 16px; */
    right: 16px;
    position: absolute;
    top: 16px;
    width: 24px;
    z-index: 3;
    color:#000 !important;
}


.accordionheader .accordionheader-x-toggle svg {
  fill: #000;
  height: 12px;
  left: 50%;
  position: absolute;
  top: 50%;
  -webkit-transform: translate(-50%, -50%);
  transform: translate(-50%, -50%);
  -webkit-transition: fill 0.25s ease-in-out, opacity 0.25s ease-in-out,
    -webkit-transform 0.25s ease-in-out;
  transition: fill 0.25s ease-in-out, opacity 0.25s ease-in-out,
    -webkit-transform 0.25s ease-in-out;
  transition: fill 0.25s ease-in-out, opacity 0.25s ease-in-out,
    transform 0.25s ease-in-out;
  transition: fill 0.25s ease-in-out, opacity 0.25s ease-in-out,
    transform 0.25s ease-in-out, -webkit-transform 0.25s ease-in-out;
  width: 12px;
  will-change: fill, opacity;
}
.accordionheader.accordionheader-is-open {
  height: auto;
}
.accordionheader.accordionheader-is-open .accordionheader-x-toggle svg {
  -webkit-transform: translate(-50%, -50%) rotate(180deg);
  transform: translate(-50%, -50%) rotate(180deg);
}
.accordionheader.accordionheader-is-open
  > .accordionheader-x-toggle
  > .accordionheader-x-iconexpand {
  opacity: 0;
}
.accordionheader.accordionheader-is-open
  > .accordionheader-x-toggle
  > .accordionheader-x-iconminimize {
  opacity: 1;
}
.accordionheader.accordionheader-is-open > .accordionheader-x-nested {
  opacity: 1;
  pointer-events: auto;
  -webkit-transform: none;
  transform: none;
}
@media (min-width: 768px) {
  .accordionheader .accordionheader-x-button {
    display: inherit;
  }
}

