  background-color: rgba(63, 63, 63, 0.7);
  -webkit-box-sizing: border-box;
  box-sizing: border-box;
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  opacity: 0;
  overflow-y: auto;
  padding: 16px;
  pointer-events: none;
  -webkit-transition: opacity 0.25s ease-in-out;
  transition: opacity 0.25s ease-in-out;
}
.dialog .dialog-x-content {
  background-color: #fff;
  margin: auto;
  max-width: 500px;
  min-height: 50px;
  position: relative;
  width: 100%;
}
.dialog .dialog-x-close {
  position: absolute;
  right: 8px;
  top: 8px;
}
.dialog.dialog-is-open {
  opacity: 1;
  pointer-events: auto;
}

.dialog-navigation {
  padding: 0;
}
.dialog-navigation .dialog-x-content {
  -webkit-box-shadow: 1px 0 0 0 #d8d8d8;
  box-shadow: 1px 0 0 0 #d8d8d8;
  -webkit-box-sizing: border-box;
  box-sizing: border-box;
  height: 100%;
  left: 0;
  margin: 0;
  max-height: none;
  max-width: none;
  overflow-y: auto;
  -webkit-transform: translateX(-100%);
  transform: translateX(-100%);
  -webkit-transition: -webkit-transform 0.25s ease-in-out;
  transition: -webkit-transform 0.25s ease-in-out;
  transition: transform 0.25s ease-in-out;
  transition: transform 0.25s ease-in-out, -webkit-transform 0.25s ease-in-out;
  width: 100%;
  will-change: transform;
}
.dialog-navigation.dialog-is-open .dialog-x-content {
  -webkit-transform: none;
  transform: none;
}
