/*Number*/
.ql-editor ol > li {
  counter-increment: numberListStyle;
  list-style: none;
}

.ql-editor ol > li:before {
  content: counter(numberListStyle) ". ";
}

.ql-editor ol > li:first-child {
  counter-reset: numberListStyle;
}

/*Alphanumeric*/

.ql-editor ol ol > li {
  counter-increment: alphaListStyle;
  list-style: none;
}

.ql-editor ol ol > li:before {
  content: counter(alphaListStyle, lower-alpha) ". ";
}

.ql-editor ol ol > li:first-child {
  counter-reset: alphaListStyle;
}
/*Roman*/

.ql-editor ol ol ol > li {
  counter-increment: romanListStyle;
  list-style: none !important;
}

.ql-editor ol ol ol > li:before {
  content: counter(romanListStyle, lower-roman) ". ";
}

.ql-editor ol ol ol > li:first-child {
  counter-reset: romanListStyle;
}

