<script type="text/javascript">
    function searchCourseProgram(searchUrl, barUrl, tenant, searchId) {
        var searchType = document.querySelector('input[name="searchType-'+searchId+'"]:checked');
        var element = document.getElementById('inputSearch-'+searchId);
		var searchValue = element.value;
		if ('courses' == searchType.value) {
			searchValue = getCourseCodeWithoutSpace(searchValue);
		}
		
        loadContent(searchUrl + '?searchType=' + searchType.value + '&text=' + searchValue + tenant,
                barUrl + '?searchType=' + searchType.value + '&text=' + searchValue);
    }
	
	function getCourseCodeWithoutSpace(searchValue) {
		var courseNumber = searchValue.match(/\d+/g);
		var code = '';
		if (courseNumber == null) {
			code = searchValue;
		}else{
			code = searchValue.replace(courseNumber, ' '+courseNumber);
		}
		
		return code;
	}

    function loadSVG(url) {
        var ajax = new XMLHttpRequest();
        ajax.open('GET', url, true);
        ajax.send();
        ajax.onload = function(e) {
            var div = document.createElement('div');
            div.innerHTML = ajax.responseText;
            div.style.display = 'none';
            document.body.insertBefore(div, document.body.childNodes[0]);
        }
    }
    loadSVG('https://elumencatalog.s3.us-west-2.amazonaws.com/dvc.elumenapp.com/Responsive-Design-template/images/svg-defs.svg');
    loadSVG('https://elumencatalog.s3.us-west-2.amazonaws.com/dvc.elumenapp.com/Responsive-Design-template/images/logos.svg');

	let currentPage = '';
    function loadContent(contentUrl, locationUrl, saveHistory = true) {
		currentPage = document.activeElement.innerText;
        var loading = document.getElementById('loading');
        var div = document.getElementById('mainContent');
		document.title = document.activeElement.innerText;

        div.innerHTML = "";
        loading.style.display = "inline";
        var ajax = new XMLHttpRequest();
        ajax.open('GET', contentUrl, true);
        ajax.send();
        ajax.onload = function(e) {
            div.innerHTML = ajax.responseText;
            loading.style.display = "none";
            reinsertScripts(div);
            if (saveHistory) {
                history.pushState({location: contentUrl, back: locationUrl}, null, locationUrl);
            } else {
                history.replaceState({location: contentUrl, back: locationUrl}, null, locationUrl);
            }
			if(locationUrl.indexOf('#') != -1) {
				var idElelement = locationUrl.substring(locationUrl.indexOf('#')+1);
				var focusElement = document.getElementById(idElelement);
				if(focusElement) {
					focusElement.scrollIntoView({block: "start", behavior : "smooth"});
					document.getElementById('landmark-main').focus();// DG-1459
				}
			}
        }
    }

    function reinsertScripts(div) {
        const scripts = div.getElementsByTagName('script');
        const scriptsInitialLength = scripts.length;
        for (var i = 0; i < scriptsInitialLength; i++) {
            const script = scripts[i];
            const scriptCopy = document.createElement('script');
            scriptCopy.type = script.type ? script.type : 'text/javascript';
            if (script.innerHTML) {
                scriptCopy.innerHTML = script.innerHTML;
            } else if (script.src) {
                scriptCopy.src = script.src;
            }
            scriptCopy.async = false;
            script.parentNode.replaceChild(scriptCopy, script);
        }
    }

    window.addEventListener("popstate", function(e) {
        loadContent(e.state.location, e.state.back, false);
    });
	
	function markNav(elem, divId) {
		var name = "active";
		var navMenu = document.getElementById(divId);
		var x = navMenu.getElementsByClassName("active");
		var i;
		for (i = 0; i < x.length; i++) {
			x[i].className = x[i].className.replace("active", "");
		}
		var arr = elem.className.split(" ");
		if (arr.indexOf(name) === -1) {
			elem.className += " " + name;
		}
	}
	
	function expandMenu(activeElement, mustExpand) {
		var firstParent = activeElement.parentNode;
		if(!firstParent.classList.contains("l-sitecontainer-x-navitems") && !firstParent.classList.contains("u-padding-xaxis2x")) {
			expandMenu(firstParent, true);
		}
		
		if(firstParent.classList.contains("accordionheader") && firstParent.classList.contains("accordionheader-nav") && mustExpand){
				firstParent.classList.toggle('accordionheader-is-open');
		}
	}
	
	async function checkIdentifier() {
		if(window.location.hash) {
			var hash = window.location.hash.substring(1); 
			var focusElement = document.getElementById(hash);
			if(focusElement) {
				await sleep(1000);
				focusElement.scrollIntoView({block: "start", behavior : "smooth"});
			}
		}
	}
	
	function sleep(ms) {
		return new Promise(resolve => setTimeout(resolve, ms));
	}

    function focusMenu() {
        document.getElementById('menu').classList.toggle('dialog-is-open');
        var mobileMenu = document.getElementById('menu');
        if (mobileMenu.classList.contains('dialog-is-open')) {
            document.getElementById('close-button').focus();
        }
        disableMainContent();
    }

    function closeNav() {
        document.getElementById('menu').classList.toggle('dialog-is-open');
        enableMainContent();
    }

    function enableMainContent() {
        document.getElementsByClassName('catalog-header')[0].removeAttribute('inert');
        document.getElementById('mainContent').removeAttribute('inert');
        document.getElementsByClassName('catalog-footer')[0].removeAttribute('inert');
    }

    function disableMainContent() {
        document.getElementsByClassName('catalog-header')[0].setAttribute('inert', 'inert');
        document.getElementById('mainContent').setAttribute('inert', 'inert');
        document.getElementsByClassName('catalog-footer')[0].setAttribute('inert', 'inert');
    }
	
	let isNavBtnShowing = false;
    function checkZoom() {
		const btnNav = document.getElementById('btn_nav');
		const btnNavStyle = window.getComputedStyle(btnNav);		
		const isVisibleNavBtn = btnNavStyle.display !== 'none' && btnNavStyle.visibility !== 'hidden';

        if (isVisibleNavBtn) {
			if (!isNavBtnShowing) {
				focusMenu();			
			}

			isNavBtnShowing = true;
        }else {
			isNavBtnShowing = false;
		 	document.getElementById('menu').classList.remove('dialog-is-open');
		}
	}
	
    document.addEventListener('keyup', function(event) {
		let activeElement = document.activeElement;

        if (event.key === 'Tab' && event.shiftKey) {
			// go back tab + shift
			let elementInContent = document.getElementById('mainContent').contains(activeElement);
			let elementInNav = document.getElementById('nav').contains(activeElement);
			let activePage = document.getElementById("landmark-navigation").getElementsByClassName("active")[0].innerText;

			if ((currentPage == activePage) && (elementInNav && !elementInContent)) {
				// focus on element
				document.getElementById("landmark-navigation").getElementsByClassName("active")[0].focus();
				currentPage = activeElement.innerText;
			}
        }		
    });

    window.addEventListener('resize', checkZoom);
    window.addEventListener('load', checkZoom);

   checkIdentifier();
</script>

